#include "kernel.h"
#include <cuda_runtime.h>
#include <cuda_bf16.h>

// ============================================================================
// Fused dropout backward + softmax backward
// ============================================================================
// Each block handles one (batch, head, query) row of length S_kv.
// We process the row in tiles to compute:
//   1. grad_attn_weights[i] = grad_dropped[i] * mask[i] / (1-p)
//   2. sum_term = sum_i(grad_attn_weights[i] * attn_weights[i])
//   3. grad_scores[i] = attn_weights[i] * (grad_attn_weights[i] - sum_term)

// Warp-level reduction
__device__ inline float warp_reduce_sum(float val) {
    for (int offset = 16; offset > 0; offset >>= 1) {
        val += __shfl_down_sync(0xFFFFFFFF, val, offset);
    }
    return val;
}

// Block-level reduction using shared memory
__device__ float block_reduce_sum(float val, float* shared, int tid, int block_size) {
    // Warp-level reduction first
    int warp_id = tid / 32;
    int lane_id = tid % 32;
    val = warp_reduce_sum(val);

    if (lane_id == 0) {
        shared[warp_id] = val;
    }
    __syncthreads();

    int num_warps = (block_size + 31) / 32;
    val = (tid < num_warps) ? shared[tid] : 0.0f;
    if (warp_id == 0) {
        val = warp_reduce_sum(val);
    }
    __syncthreads();

    return val; // valid in thread 0 of warp 0
}

__global__ void fused_dropout_softmax_backward_kernel(
    __nv_bfloat16* __restrict__ grad_attn_scores,
    const float* __restrict__ grad_attn_weights_dropped,
    const __nv_bfloat16* __restrict__ attn_weights,
    const bool* __restrict__ dropout_mask,
    const float inv_keep_prob,  // 1.0 / (1.0 - p)
    const int seq_len_kv)
{
    // Each block processes one row: (batch, head, query_pos)
    // blockIdx.x = row index into the flattened [B*H*S_q] dimension
    const int row = blockIdx.x;
    const int tid = threadIdx.x;

    const int row_offset = row * seq_len_kv;
    const float* grad_dropped_row = grad_attn_weights_dropped + row_offset;
    const __nv_bfloat16* attn_w_row = attn_weights + row_offset;
    const bool* mask_row = dropout_mask + row_offset;
    __nv_bfloat16* out_row = grad_attn_scores + row_offset;

    extern __shared__ float smem[];

    // Pass 1: compute grad_attn_weights and dot product sum
    float local_sum = 0.0f;
    for (int i = tid; i < seq_len_kv; i += blockDim.x) {
        float gd = grad_dropped_row[i];
        float m = mask_row[i] ? 1.0f : 0.0f;
        float gw = gd * m * inv_keep_prob;
        float aw = __bfloat162float(attn_w_row[i]);
        local_sum += gw * aw;
    }

    // Block-wide reduction for sum_term
    // Use smem for warp partial sums
    float sum_term = block_reduce_sum(local_sum, smem, tid, blockDim.x);
    // Broadcast sum_term to all threads
    if (tid == 0) {
        smem[0] = sum_term;
    }
    __syncthreads();
    sum_term = smem[0];

    // Pass 2: compute output
    for (int i = tid; i < seq_len_kv; i += blockDim.x) {
        float gd = grad_dropped_row[i];
        float m = mask_row[i] ? 1.0f : 0.0f;
        float gw = gd * m * inv_keep_prob;
        float aw = __bfloat162float(attn_w_row[i]);
        float result = aw * (gw - sum_term);
        out_row[i] = __float2bfloat16(result);
    }
}

void fused_dropout_softmax_backward_launcher(
    torch::Tensor& grad_attn_scores,
    const torch::Tensor& grad_attn_weights_dropped,
    const torch::Tensor& attn_weights,
    const torch::Tensor& dropout_mask,
    float dropout_prob,
    cudaStream_t stream)
{
    const int batch_size = grad_attn_weights_dropped.size(0);
    const int num_heads = grad_attn_weights_dropped.size(1);
    const int seq_len_q = grad_attn_weights_dropped.size(2);
    const int seq_len_kv = grad_attn_weights_dropped.size(3);

    const int total_rows = batch_size * num_heads * seq_len_q;
    const float inv_keep_prob = 1.0f / (1.0f - dropout_prob);

    // Choose block size based on seq_len_kv
    int block_size = 256;
    if (seq_len_kv >= 2048) block_size = 512;
    if (seq_len_kv >= 4096) block_size = 1024;

    int num_warps = (block_size + 31) / 32;
    int shared_mem = num_warps * sizeof(float);

    fused_dropout_softmax_backward_kernel<<<total_rows, block_size, shared_mem, stream>>>(
        reinterpret_cast<__nv_bfloat16*>(grad_attn_scores.data_ptr<at::BFloat16>()),
        grad_attn_weights_dropped.data_ptr<float>(),
        reinterpret_cast<const __nv_bfloat16*>(attn_weights.data_ptr<at::BFloat16>()),
        dropout_mask.data_ptr<bool>(),
        inv_keep_prob,
        seq_len_kv
    );
}


// ============================================================================
// GQA aggregation kernel
// ============================================================================
// Reshapes [B, H, S_kv, D] → [B, H_kv, G, S_kv, D] and sums over G
// Each block handles one (batch, kv_head, s_kv) element, summing G groups of D values

__global__ void gqa_aggregate_kernel(
    __nv_bfloat16* __restrict__ output,  // [B, H_kv, S_kv, D]
    const float* __restrict__ input,      // [B, H, S_kv, D]
    const int num_kv_heads,
    const int num_groups,
    const int seq_len_kv,
    const int head_dim)
{
    // blockIdx.x = flattened (batch, kv_head, s_kv) index
    // threadIdx.x = position in head_dim
    const int idx = blockIdx.x;
    const int d = threadIdx.x;

    if (d >= head_dim) return;

    const int total_per_batch = num_kv_heads * seq_len_kv;
    const int b = idx / total_per_batch;
    const int rem = idx % total_per_batch;
    const int kv_head = rem / seq_len_kv;
    const int s = rem % seq_len_kv;

    const int num_heads = num_kv_heads * num_groups;

    // Sum over groups
    float acc = 0.0f;
    for (int g = 0; g < num_groups; g++) {
        int h = kv_head * num_groups + g;
        // input layout: [B, H, S_kv, D]
        int in_idx = ((b * num_heads + h) * seq_len_kv + s) * head_dim + d;
        acc += input[in_idx];
    }

    // output layout: [B, H_kv, S_kv, D]
    int out_idx = ((b * num_kv_heads + kv_head) * seq_len_kv + s) * head_dim + d;
    output[out_idx] = __float2bfloat16(acc);
}

void gqa_aggregate_launcher(
    torch::Tensor& grad_value_states,
    const torch::Tensor& grad_value_expanded,
    int num_kv_heads,
    int num_groups,
    cudaStream_t stream)
{
    const int batch_size = grad_value_expanded.size(0);
    const int seq_len_kv = grad_value_expanded.size(2);
    const int head_dim = grad_value_expanded.size(3);

    const int total_blocks = batch_size * num_kv_heads * seq_len_kv;
    const int block_size = head_dim;  // 128 threads, one per element in head_dim

    gqa_aggregate_kernel<<<total_blocks, block_size, 0, stream>>>(
        reinterpret_cast<__nv_bfloat16*>(grad_value_states.data_ptr<at::BFloat16>()),
        grad_value_expanded.data_ptr<float>(),
        num_kv_heads,
        num_groups,
        seq_len_kv,
        head_dim
    );
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include "kernel.h"

/**
 * Backward pass for attention softmax, dropout, and value matmul.
 *
 * Optimizations over baseline:
 * 1. Fused dropout+softmax backward kernel (avoids materializing grad_attn_weights)
 * 2. Fused GQA aggregation kernel (avoids reshape+sum overhead)
 * 3. cuBLAS for the two large batched matmuls
 */
std::vector<torch::Tensor> run(
    const torch::Tensor& grad_attn_output,     // [B, S_q, H, D] bf16
    const torch::Tensor& attn_weights,          // [B, H, S_q, S_kv] bf16
    const torch::Tensor& attn_weights_dropped,  // [B, H, S_q, S_kv] bf16
    const torch::Tensor& value_states,           // [B, H_kv, S_kv, D] bf16
    const torch::Tensor& dropout_mask,           // [B, H, S_q, S_kv] bool
    double attention_dropout)                    // scalar
{
    constexpr int NUM_ATTENTION_HEADS = 80;
    constexpr int NUM_KEY_VALUE_HEADS = 8;
    constexpr int NUM_KEY_VALUE_GROUPS = NUM_ATTENTION_HEADS / NUM_KEY_VALUE_HEADS; // 10
    constexpr int HEAD_DIM = 128;

    const int batch_size = grad_attn_output.size(0);
    const int seq_len_q = grad_attn_output.size(1);
    const int seq_len_kv = value_states.size(2);

    cudaStream_t stream = at::cuda::getCurrentCUDAStream();
    float dropout_p = static_cast<float>(attention_dropout);

    // 1. Transpose and cast grad_attn_output: [B, S_q, H, D] -> [B, H, S_q, D] fp32
    auto grad_attn_output_t = grad_attn_output.transpose(1, 2).contiguous().to(torch::kFloat32);

    // 2. Expand value_states for GQA: [B, H_kv, S_kv, D] -> [B, H, S_kv, D]
    auto value_states_expanded = value_states.unsqueeze(2)
        .expand({batch_size, NUM_KEY_VALUE_HEADS, NUM_KEY_VALUE_GROUPS, seq_len_kv, HEAD_DIM})
        .reshape({batch_size, NUM_ATTENTION_HEADS, seq_len_kv, HEAD_DIM})
        .to(torch::kFloat32);

    // 3. MatMul 1: grad_attn_weights_dropped = grad_output_t @ V_expanded^T
    //    [B, H, S_q, D] @ [B, H, D, S_kv] -> [B, H, S_q, S_kv]  (fp32)
    auto grad_attn_weights_dropped = torch::matmul(
        grad_attn_output_t,
        value_states_expanded.transpose(-2, -1)
    );

    // 4+5. Fused dropout backward + softmax backward
    auto grad_attn_scores = torch::empty(
        {batch_size, NUM_ATTENTION_HEADS, seq_len_q, seq_len_kv},
        attn_weights.options()  // bf16
    );

    fused_dropout_softmax_backward_launcher(
        grad_attn_scores,
        grad_attn_weights_dropped,
        attn_weights,
        dropout_mask,
        dropout_p,
        stream
    );

    // 6. MatMul 2: grad_value_expanded = attn_weights_dropped^T @ grad_output_t
    //    [B, H, S_kv, S_q] @ [B, H, S_q, D] -> [B, H, S_kv, D]  (fp32)
    auto attn_weights_dropped_f32 = attn_weights_dropped.to(torch::kFloat32);
    auto grad_value_expanded = torch::matmul(
        attn_weights_dropped_f32.transpose(-2, -1),
        grad_attn_output_t
    );

    // 7. Fused GQA aggregation: [B, H, S_kv, D] -> [B, H_kv, S_kv, D] bf16
    auto grad_value_states = torch::empty(
        {batch_size, NUM_KEY_VALUE_HEADS, seq_len_kv, HEAD_DIM},
        value_states.options()  // bf16
    );

    gqa_aggregate_launcher(
        grad_value_states,
        grad_value_expanded,
        NUM_KEY_VALUE_HEADS,
        NUM_KEY_VALUE_GROUPS,
        stream
    );

    return {grad_attn_scores, grad_value_states};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Attention backward pass (softmax + dropout + value matmul)");
}
